#ifndef LOW_PASS_FILTER_H
#define LOW_PASS_FILTER_H
#include <Arduino.h>

class LowPassFilter {
public:
    LowPassFilter(float alpha = 0.3f);
    float update(float newValue);
    float getValue() const;
    void setAlpha(float alpha);
    void reset(float value = 0.0f);
private:
    float _alpha;
    float _output;
    bool _initialized;
};

#endif

firmware_template.source:
#include "low_pass_filter.h"

LowPassFilter::LowPassFilter(float alpha)
    : _alpha(constrain(alpha, 0.0f, 1.0f)), _output(0.0f), _initialized(false) {}

float LowPassFilter::update(float newValue) {
    if (!_initialized) {
        _output = newValue;
        _initialized = true;
    } else {
        _output = _alpha * newValue + (1.0f - _alpha) * _output;
    }
    return _output;
}

float LowPassFilter::getValue() const { return _output; }

void LowPassFilter::setAlpha(float alpha) {
    _alpha = constrain(alpha, 0.0f, 1.0f);
}

void LowPassFilter::reset(float value) {
    _output = value; _initialized = false;
}
